((w,d)=>{var t=w.localStorage.getItem('_theme');if(!t){w.localStorage.setItem('_theme','dark-mode');t='dark-mode'}if(t==='dark-mode'){d.body.classList.add('dark-mode');d.body.classList.remove('light-mode')}else{d.body.classList.add('light-mode');d.body.classList.remove('dark-mode')}})(window,document);
